const chainOutput = $input.first().json;
const buildInput = $('Build Custom Prompt').first().json;

const rawOutput = (chainOutput.response && chainOutput.response.text)
               || chainOutput.text
               || chainOutput.output
               || (typeof chainOutput.response === 'string' ? chainOutput.response : '')
               || '';

console.log('=== WF-04C Parse Response ===');
console.log('keys:', JSON.stringify(Object.keys(chainOutput)));
console.log('rawOutput preview:', rawOutput.substring(0, 200));

let parsed = null;
try {
  let clean = rawOutput.trim();
  if (clean.startsWith('```')) clean = clean.replace(/^```json?\n?/, '').replace(/\n?```$/, '');
  const jStart = clean.indexOf('{');
  const jEnd = clean.lastIndexOf('}');
  if (jStart !== -1 && jEnd !== -1) clean = clean.substring(jStart, jEnd + 1);
  parsed = JSON.parse(clean);
} catch(e) {
  console.log('Parse error:', e.message);
  parsed = {
    resume_executif:      rawOutput.substring(0, 500) || 'Analyse générée',
    executive_summary:    rawOutput.substring(0, 500) || 'Analysis generated',
    analyse_ciblee:       { points_cles: [], tendances_detectees: [], anomalies: [] },
    focused_analysis:     { key_findings: [], patterns_detected: [], anomalies: [] },
    insights:             [],
    recommandations:      [],
    recommendations:      [],
    adaptation_audience:  '',
    audience_adaptation:  '',
    score_qualite_donnees: '?',
    data_quality_score:   '?',
    limites:              'Erreur parsing JSON',
    limitations:          'JSON parsing error',
    parse_error:          true
  };
}

return [{ json: {
  parsed_response:  parsed,
  raw_output:       rawOutput,
  session_id:       buildInput.session_id,
  chat_id:          buildInput.chat_id,
  language:         buildInput.language,
  file_name:        buildInput.file_name,
  custom_answers:   buildInput.custom_answers,
  start_time:       buildInput.start_time
} }];

const data = $input.first().json;
const r = data.parsed_response;
const lang = data.language;
const answers = data.custom_answers || {};
const responseMs = Date.now() - (data.start_time || Date.now());

let report = '';

if (lang === 'ENG') {
  const summary   = r.executive_summary || 'N/A';
  const findings  = (r.focused_analysis && r.focused_analysis.key_findings ? r.focused_analysis.key_findings : (r.insights || [])).slice(0, 4);
  const patterns  = (r.focused_analysis && r.focused_analysis.patterns_detected ? r.focused_analysis.patterns_detected : []).slice(0, 3);
  const insights  = (r.insights || []).slice(0, 3);
  const recs      = (r.recommendations || []).slice(0, 3);
  const quality   = r.data_quality_score || '?';
  const audience  = r.audience_adaptation || '';
  const limits    = r.limitations || 'None';

  report = '📊 *PERSONALIZED ANALYSIS — ' + data.file_name + '*\n'
    + '_Target: ' + (answers.q5 || 'General') + '_\n\n'
    + '━━━━━━━━━━━━━━━━━━━━━━━\n'
    + '📋 *EXECUTIVE SUMMARY*\n'
    + '━━━━━━━━━━━━━━━━━━━━━━━\n'
    + summary + '\n\n'
    + '━━━━━━━━━━━━━━━━━━━━━━━\n'
    + '🔍 *KEY FINDINGS*\n'
    + '━━━━━━━━━━━━━━━━━━━━━━━\n'
    + (findings.length ? findings.map(function(f,i){return (i+1)+'. '+f;}).join('\n') : 'N/A') + '\n'
    + (patterns.length ? '\n📈 *PATTERNS*\n' + patterns.map(function(p){return '• '+p;}).join('\n') + '\n' : '')
    + '\n━━━━━━━━━━━━━━━━━━━━━━━\n'
    + '💡 *INSIGHTS*\n'
    + '━━━━━━━━━━━━━━━━━━━━━━━\n'
    + (insights.length ? insights.map(function(ins,i){return (i+1)+'. '+ins;}).join('\n') : 'N/A') + '\n\n'
    + '━━━━━━━━━━━━━━━━━━━━━━━\n'
    + '✅ *RECOMMENDATIONS*\n'
    + '━━━━━━━━━━━━━━━━━━━━━━━\n'
    + (recs.length ? recs.map(function(rec,i){return (i+1)+'. '+rec;}).join('\n') : 'N/A') + '\n'
    + (audience ? '\n🎯 *AUDIENCE ADAPTATION*\n' + audience + '\n' : '')
    + '\n━━━━━━━━━━━━━━━━━━━━━━━\n'
    + '📊 Quality: ' + quality + '/10 | Goal: ' + (answers.q1 || 'N/A') + '\n'
    + (limits !== 'None' ? '⚠️ Limits: ' + limits + '\n' : '')
    + '_' + responseMs + 'ms · Personalized analysis · Intelligence Bot_';

} else {
  const summary   = r.resume_executif || r.executive_summary || 'N/A';
  const findings  = (r.analyse_ciblee && r.analyse_ciblee.points_cles ? r.analyse_ciblee.points_cles : (r.insights || [])).slice(0, 4);
  const tendances = (r.analyse_ciblee && r.analyse_ciblee.tendances_detectees ? r.analyse_ciblee.tendances_detectees : []).slice(0, 3);
  const insights  = (r.insights || []).slice(0, 3);
  const recs      = (r.recommandations || r.recommendations || []).slice(0, 3);
  const quality   = r.score_qualite_donnees || r.data_quality_score || '?';
  const audience  = r.adaptation_audience || r.audience_adaptation || '';
  const limits    = r.limites || r.limitations || 'Aucune';

  report = '📊 *ANALYSE PERSONNALISÉE — ' + data.file_name + '*\n'
    + '_Audience : ' + (answers.q5 || 'Général') + '_\n\n'
    + '━━━━━━━━━━━━━━━━━━━━━━━\n'
    + '📋 *RÉSUMÉ EXÉCUTIF*\n'
    + '━━━━━━━━━━━━━━━━━━━━━━━\n'
    + summary + '\n\n'
    + '━━━━━━━━━━━━━━━━━━━━━━━\n'
    + '🔍 *POINTS CLÉS*\n'
    + '━━━━━━━━━━━━━━━━━━━━━━━\n'
    + (findings.length ? findings.map(function(f,i){return (i+1)+'. '+f;}).join('\n') : 'N/A') + '\n'
    + (tendances.length ? '\n📈 *TENDANCES*\n' + tendances.map(function(t){return '• '+t;}).join('\n') + '\n' : '')
    + '\n━━━━━━━━━━━━━━━━━━━━━━━\n'
    + '💡 *INSIGHTS*\n'
    + '━━━━━━━━━━━━━━━━━━━━━━━\n'
    + (insights.length ? insights.map(function(ins,i){return (i+1)+'. '+ins;}).join('\n') : 'N/A') + '\n\n'
    + '━━━━━━━━━━━━━━━━━━━━━━━\n'
    + '✅ *RECOMMANDATIONS*\n'
    + '━━━━━━━━━━━━━━━━━━━━━━━\n'
    + (recs.length ? recs.map(function(rec,i){return (i+1)+'. '+rec;}).join('\n') : 'N/A') + '\n'
    + (audience ? '\n🎯 *ADAPTATION AUDIENCE*\n' + audience + '\n' : '')
    + '\n━━━━━━━━━━━━━━━━━━━━━━━\n'
    + '📊 Qualité : ' + quality + '/10 | Objectif : ' + (answers.q1 || 'N/A') + '\n'
    + (limits !== 'Aucune' ? '⚠️ Limites : ' + limits + '\n' : '')
    + '_' + responseMs + 'ms · Analyse personnalisée · Intelligence Bot_';
}

if (report.length > 4096) report = report.substring(0, 4090) + '..._';

const rawResponseB64 = Buffer.from(JSON.stringify(r)).toString('base64');

return [{ json: {
  report_text:      report,
  session_id:       data.session_id,
  chat_id:          data.chat_id,
  language:         lang,
  raw_response_b64: rawResponseB64
} }];
